mapper.insert:
insert into user (user_code, user_password, user_nickname, user_term_initial_date, user_current_date, user_current_week)
select #{user.userCode}, #{user.userPassword}, #{user.userNickname}, #{user.termInitialDate}, #{user.currentDate}, #{user.currentWeek}
where not exists (select #{user.userCode} from user where user_code = #{user.userCode});

mapper.update:
update user
set user_current_date = #{currentDate}, user_current_week = #{currentWeek}
where user_code = #{userCode};

update user
set user_password = #{userPassword}
where user_code = #{userCode};

mapper.delete:
delete
from user
where user_code = #{userCode} and user_password = #{userPassword};
